package com.twiliocommkit.android

import android.app.Activity
import android.content.Intent
import io.flutter.embedding.engine.plugins.FlutterPlugin
import io.flutter.embedding.engine.plugins.activity.ActivityAware
import io.flutter.embedding.engine.plugins.activity.ActivityPluginBinding
import io.flutter.plugin.common.EventChannel
import io.flutter.plugin.common.MethodCall
import io.flutter.plugin.common.MethodChannel
import io.flutter.plugin.common.MethodChannel.MethodCallHandler
import io.flutter.plugin.common.MethodChannel.Result
import io.flutter.plugin.common.PluginRegistry
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.cancel

import com.twiliocommkit.android.video.TwilioVideoManager
import com.twiliocommkit.android.voice.TwilioVoiceManager
import com.twiliocommkit.android.voice.TwilioVoiceNotificationHandler
import com.twiliocommkit.android.voice.TwilioIncomingCallActivity
import com.twiliocommkit.android.core.TwilioEventSink
import com.twiliocommkit.android.core.TwilioSdkCredentials
import com.twiliocommkit.android.video.TwilioVideoViewFactory

/**
 * Flutter plugin entry point for the Android Twilio CommKit implementation.
 */
class FlutterTwilioCommKitAndroidPlugin : FlutterPlugin, MethodCallHandler,
    ActivityAware, PluginRegistry.NewIntentListener {

    private lateinit var methodChannel: MethodChannel
    private lateinit var callHandlerChannel: MethodChannel
    private lateinit var videoEventChannel: EventChannel
    private lateinit var voiceEventChannel: EventChannel

    private val coroutineScope = CoroutineScope(SupervisorJob() + Dispatchers.Main)

    private lateinit var videoManager: TwilioVideoManager
    private lateinit var voiceManager: TwilioVoiceManager

    private val videoEventSink = TwilioEventSink()
    private val voiceEventSink = TwilioEventSink()

    // Pending incoming call from a launch/new intent (app was killed or in background)
    private var pendingCallSid: String? = null
    private var pendingFrom: String? = null
    private var pendingAccepted: Boolean = false

    override fun onAttachedToEngine(binding: FlutterPlugin.FlutterPluginBinding) {
        val context = binding.applicationContext

        methodChannel = MethodChannel(binding.binaryMessenger, "com.twiliocommkit/methods")
        methodChannel.setMethodCallHandler(this)

        // Dedicated channel for the SDK's TwilioCallHandler to query pending calls
        callHandlerChannel = MethodChannel(binding.binaryMessenger, "com.twiliocommkit/incoming_call")
        callHandlerChannel.setMethodCallHandler { call, result ->
            when (call.method) {
                "getPendingIncomingCall" -> {
                    if (pendingCallSid != null) {
                        result.success(mapOf(
                            "callSid" to (pendingCallSid ?: ""),
                            "from" to (pendingFrom ?: "Unknown"),
                            "accepted" to pendingAccepted
                        ))
                        pendingCallSid = null
                        pendingFrom = null
                        pendingAccepted = false
                    } else {
                        result.success(null)
                    }
                }
                else -> result.notImplemented()
            }
        }

        videoEventChannel = EventChannel(binding.binaryMessenger, "com.twiliocommkit/video_events")
        videoEventChannel.setStreamHandler(videoEventSink)

        voiceEventChannel = EventChannel(binding.binaryMessenger, "com.twiliocommkit/voice_events")
        voiceEventChannel.setStreamHandler(voiceEventSink)

        videoManager = TwilioVideoManager(context, videoEventSink, coroutineScope)
        voiceManager = TwilioVoiceManager(context, voiceEventSink, coroutineScope)

        binding.platformViewRegistry.registerViewFactory(
            "com.twiliocommkit/video_view",
            TwilioVideoViewFactory(videoManager.trackRegistry)
        )
    }

    // ── ActivityAware — needed to read the launch intent ─────────────────────

    override fun onAttachedToActivity(binding: ActivityPluginBinding) {
        binding.addOnNewIntentListener(this)
        handleIntent(binding.activity.intent)
    }

    override fun onReattachedToActivityForConfigChanges(binding: ActivityPluginBinding) {
        binding.addOnNewIntentListener(this)
    }

    override fun onDetachedFromActivityForConfigChanges() {}

    override fun onDetachedFromActivity() {}

    override fun onNewIntent(intent: Intent): Boolean {
        handleIntent(intent)
        return false
    }

    private fun handleIntent(intent: Intent?) {
        if (intent?.action == TwilioVoiceNotificationHandler.ACTION_INCOMING_CALL) {
            pendingCallSid = intent.getStringExtra(TwilioVoiceNotificationHandler.EXTRA_CALL_SID)
            pendingFrom = intent.getStringExtra(TwilioVoiceNotificationHandler.EXTRA_FROM)
                ?.removePrefix("client:") ?: "Unknown"
            pendingAccepted = intent.getBooleanExtra(TwilioIncomingCallActivity.EXTRA_ACCEPTED, false)
            TwilioLogger.debug("Plugin: incoming call intent received sid=$pendingCallSid accepted=$pendingAccepted")
        }
    }

    // ── Main method channel ───────────────────────────────────────────────────

    override fun onMethodCall(call: MethodCall, result: Result) {
        when (call.method) {
            "initialize" -> {
                val logLevel = call.argument<String>("logLevel") ?: "none"
                TwilioLogger.configure(logLevel)

                val credMap = call.argument<Map<String, Any?>>("credentials")
                if (credMap != null) {
                    val creds = TwilioSdkCredentials(
                        accountSid = credMap["accountSid"] as? String ?: "",
                        apiKeySid = credMap["apiKeySid"] as? String ?: "",
                        pushCredentialSid = credMap["pushCredentialSid"] as? String,
                        outgoingApplicationSid = credMap["outgoingApplicationSid"] as? String
                    )
                    TwilioSdkCredentials.current = creds
                    TwilioLogger.debug("Credentials configured: accountSid=${creds.accountSid}")
                }

                val videoConfig = call.argument<Map<String, Any?>>("videoConfig") ?: emptyMap()
                val voiceConfig = call.argument<Map<String, Any?>>("voiceConfig") ?: emptyMap()
                videoManager.applyConfig(videoConfig)
                voiceManager.applyConfig(voiceConfig)

                result.success(null)
            }
            "connectToRoom" -> videoManager.connectToRoom(call, result)
            "disconnectFromRoom" -> videoManager.disconnectFromRoom(call, result)
            "muteVideo" -> videoManager.muteVideo(call, result)
            "muteAudio" -> videoManager.muteAudio(call, result)
            "switchCamera" -> videoManager.switchCamera(result)
            "getParticipants" -> videoManager.getParticipants(call, result)
            "initVoice" -> voiceManager.initVoice(call, result)
            "startCall" -> voiceManager.startCall(call, result)
            "acceptCall" -> voiceManager.acceptCall(call, result)
            "rejectCall" -> voiceManager.rejectCall(call, result)
            "hangUpCall" -> voiceManager.hangUpCall(call, result)
            "muteCall" -> voiceManager.muteCall(call, result)
            "holdCall" -> voiceManager.holdCall(call, result)
            "setSpeaker" -> voiceManager.setSpeaker(call, result)
            else -> result.notImplemented()
        }
    }

    override fun onDetachedFromEngine(binding: FlutterPlugin.FlutterPluginBinding) {
        methodChannel.setMethodCallHandler(null)
        callHandlerChannel.setMethodCallHandler(null)
        videoManager.dispose()
        voiceManager.dispose()
        coroutineScope.cancel()
    }
}

package com.twiliocommkit.android

import android.app.Activity
import android.content.Intent
import io.flutter.embedding.engine.plugins.FlutterPlugin
import io.flutter.embedding.engine.plugins.activity.ActivityAware
import io.flutter.embedding.engine.plugins.activity.ActivityPluginBinding
import io.flutter.plugin.common.EventChannel
import io.flutter.plugin.common.MethodCall
import io.flutter.plugin.common.MethodChannel
import io.flutter.plugin.common.MethodChannel.MethodCallHandler
import io.flutter.plugin.common.MethodChannel.Result
import io.flutter.plugin.common.PluginRegistry
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.cancel

import com.twiliocommkit.android.video.TwilioVideoManager
import com.twiliocommkit.android.voice.TwilioVoiceManager
import com.twiliocommkit.android.voice.TwilioVoiceNotificationHandler
import com.twiliocommkit.android.voice.TwilioIncomingCallActivity
import com.twiliocommkit.android.core.TwilioEventSink
import com.twiliocommkit.android.core.TwilioSdkCredentials
import com.twiliocommkit.android.video.TwilioVideoViewFactory

/**
 * Flutter plugin entry point for the Android Twilio CommKit implementation.
 */
class FlutterTwilioCommKitAndroidPlugin : FlutterPlugin, MethodCallHandler,
    ActivityAware, PluginRegistry.NewIntentListener {

    private lateinit var methodChannel: MethodChannel
    private lateinit var callHandlerChannel: MethodChannel
    private lateinit var videoEventChannel: EventChannel
    private lateinit var voiceEventChannel: EventChannel

    private val coroutineScope = CoroutineScope(SupervisorJob() + Dispatchers.Main)

    private lateinit var videoManager: TwilioVideoManager
    private lateinit var voiceManager: TwilioVoiceManager

    private val videoEventSink = TwilioEventSink()
    private val voiceEventSink = TwilioEventSink()

    // Pending incoming call from a launch/new intent (app was killed or in background)
    private var pendingCallSid: String? = null
    private var pendingFrom: String? = null
    private var pendingAccepted: Boolean = false

    override fun onAttachedToEngine(binding: FlutterPlugin.FlutterPluginBinding) {
        val context = binding.applicationContext

        methodChannel = MethodChannel(binding.binaryMessenger, "com.twiliocommkit/methods")
        methodChannel.setMethodCallHandler(this)

        // Dedicated channel for the SDK's TwilioCallHandler to query pending calls
        callHandlerChannel = MethodChannel(binding.binaryMessenger, "com.twiliocommkit/incoming_call")
        callHandlerChannel.setMethodCallHandler { call, result ->
            when (call.method) {
                "getPendingIncomingCall" -> {
                    if (pendingCallSid != null) {
                        result.success(mapOf(
                            "callSid" to (pendingCallSid ?: ""),
                            "from" to (pendingFrom ?: "Unknown"),
                            "accepted" to pendingAccepted
                        ))
                        pendingCallSid = null
                        pendingFrom = null
                        pendingAccepted = false
                    } else {
                        result.success(null)
                    }
                }
                else -> result.notImplemented()
            }
        }

        videoEventChannel = EventChannel(binding.binaryMessenger, "com.twiliocommkit/video_events")
        videoEventChannel.setStreamHandler(videoEventSink)

        voiceEventChannel = EventChannel(binding.binaryMessenger, "com.twiliocommkit/voice_events")
        voiceEventChannel.setStreamHandler(voiceEventSink)

        videoManager = TwilioVideoManager(context, videoEventSink, coroutineScope)
        voiceManager = TwilioVoiceManager(context, voiceEventSink, coroutineScope)

        binding.platformViewRegistry.registerViewFactory(
            "com.twiliocommkit/video_view",
            TwilioVideoViewFactory(videoManager.trackRegistry)
        )
    }

    // ── ActivityAware — needed to read the launch intent ─────────────────────

    override fun onAttachedToActivity(binding: ActivityPluginBinding) {
        binding.addOnNewIntentListener(this)
        handleIntent(binding.activity.intent, fromLaunch = true)
    }

    override fun onReattachedToActivityForConfigChanges(binding: ActivityPluginBinding) {
        binding.addOnNewIntentListener(this)
    }

    override fun onDetachedFromActivityForConfigChanges() {}

    override fun onDetachedFromActivity() {}

    override fun onNewIntent(intent: Intent): Boolean {
        handleIntent(intent, fromLaunch = false)
        return false
    }

    private fun handleIntent(intent: Intent?, fromLaunch: Boolean) {
        if (intent?.action == TwilioVoiceNotificationHandler.ACTION_INCOMING_CALL) {
            val callSid  = intent.getStringExtra(TwilioVoiceNotificationHandler.EXTRA_CALL_SID)
            val from     = intent.getStringExtra(TwilioVoiceNotificationHandler.EXTRA_FROM)
                               ?.removePrefix("client:") ?: "Unknown"
            val accepted = intent.getBooleanExtra(TwilioIncomingCallActivity.EXTRA_ACCEPTED, false)
            TwilioLogger.debug("Plugin: incoming call intent fromLaunch=$fromLaunch sid=$callSid accepted=$accepted")

            if (fromLaunch) {
                // App was killed/background — store for Flutter to poll via getPendingIncomingCall
                pendingCallSid  = callSid
                pendingFrom     = from
                pendingAccepted = accepted
            } else {
                // App already running (foreground) — push directly to Flutter via method channel
                callHandlerChannel.invokeMethod("onIncomingCallResult", mapOf(
                    "callSid"  to (callSid ?: ""),
                    "from"     to from,
                    "accepted" to accepted
                ))
            }
        }
    }

    // ── Main method channel ───────────────────────────────────────────────────

    override fun onMethodCall(call: MethodCall, result: Result) {
        when (call.method) {
            "initialize" -> {
                val logLevel = call.argument<String>("logLevel") ?: "none"
                TwilioLogger.configure(logLevel)

                val credMap = call.argument<Map<String, Any?>>("credentials")
                if (credMap != null) {
                    val creds = TwilioSdkCredentials(
                        accountSid = credMap["accountSid"] as? String ?: "",
                        apiKeySid = credMap["apiKeySid"] as? String ?: "",
                        pushCredentialSid = credMap["pushCredentialSid"] as? String,
                        outgoingApplicationSid = credMap["outgoingApplicationSid"] as? String
                    )
                    TwilioSdkCredentials.current = creds
                    TwilioLogger.debug("Credentials configured: accountSid=${creds.accountSid}")
                }

                val videoConfig = call.argument<Map<String, Any?>>("videoConfig") ?: emptyMap()
                val voiceConfig = call.argument<Map<String, Any?>>("voiceConfig") ?: emptyMap()
                videoManager.applyConfig(videoConfig)
                voiceManager.applyConfig(voiceConfig)

                result.success(null)
            }
            "connectToRoom" -> videoManager.connectToRoom(call, result)
            "disconnectFromRoom" -> videoManager.disconnectFromRoom(call, result)
            "muteVideo" -> videoManager.muteVideo(call, result)
            "muteAudio" -> videoManager.muteAudio(call, result)
            "switchCamera" -> videoManager.switchCamera(result)
            "getParticipants" -> videoManager.getParticipants(call, result)
            "initVoice" -> voiceManager.initVoice(call, result)
            "startCall" -> voiceManager.startCall(call, result)
            "acceptCall" -> voiceManager.acceptCall(call, result)
            "rejectCall" -> voiceManager.rejectCall(call, result)
            "hangUpCall" -> voiceManager.hangUpCall(call, result)
            "muteCall" -> voiceManager.muteCall(call, result)
            "holdCall" -> voiceManager.holdCall(call, result)
            "setSpeaker" -> voiceManager.setSpeaker(call, result)
            else -> result.notImplemented()
        }
    }

    override fun onDetachedFromEngine(binding: FlutterPlugin.FlutterPluginBinding) {
        methodChannel.setMethodCallHandler(null)
        callHandlerChannel.setMethodCallHandler(null)
        videoManager.dispose()
        voiceManager.dispose()
        coroutineScope.cancel()
    }
}

package com.twiliocommkit.android.video

import android.content.Context
import android.hardware.camera2.CameraCharacteristics
import android.hardware.camera2.CameraManager
import com.twilio.video.*
import com.twiliocommkit.android.TwilioLogger
import com.twiliocommkit.android.core.TwilioEventSink
import io.flutter.plugin.common.MethodCall
import io.flutter.plugin.common.MethodChannel.Result
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext

/**
 * Manages Twilio Video room lifecycle on Android.
 *
 * Key fix: connectToRoom now waits for onConnected/onConnectFailure
 * before replying to Flutter, so the returned room SID is always valid.
 */
class TwilioVideoManager(
    private val context: Context,
    private val eventSink: TwilioEventSink,
    private val scope: CoroutineScope
) {

    private var room: Room? = null
    private var localAudioTrack: LocalAudioTrack? = null
    private var localVideoTrack: LocalVideoTrack? = null
    private var cameraCapturer: Camera2Capturer? = null
    private var isFrontCamera = true

    // Pending connect result — held until onConnected or onConnectFailure fires
    private var pendingConnectResult: Result? = null
    private var pendingRoomName: String = ""

    private var roomType: String = "group"
    private var enableNetworkQuality: Boolean = true
    private var preferredVideoCodec: String = "vp8"
    private var maxVideoBitrate: Int? = null
    private var maxAudioBitrate: Int? = null

    // ─── Camera helpers ──────────────────────────────────────────────────────

    private fun getCameraId(front: Boolean): String? {
        val cameraManager = context.getSystemService(Context.CAMERA_SERVICE) as CameraManager
        for (id in cameraManager.cameraIdList) {
            val facing = cameraManager
                .getCameraCharacteristics(id)
                .get(CameraCharacteristics.LENS_FACING)
            val match = if (front)
                facing == CameraCharacteristics.LENS_FACING_FRONT
            else
                facing == CameraCharacteristics.LENS_FACING_BACK
            if (match) return id
        }
        return cameraManager.cameraIdList.firstOrNull()
    }

    // ─── Config ───────────────────────────────────────────────────────────────

    fun applyConfig(config: Map<String, Any?>) {
        roomType = config["roomType"] as? String ?: "group"
        enableNetworkQuality = config["enableNetworkQuality"] as? Boolean ?: true
        preferredVideoCodec = config["preferredVideoCodec"] as? String ?: "vp8"
        maxVideoBitrate = config["maxVideoBitrate"] as? Int
        maxAudioBitrate = config["maxAudioBitrate"] as? Int
        TwilioLogger.debug("VideoManager config applied: roomType=$roomType codec=$preferredVideoCodec")
    }

    // ─── Public API ──────────────────────────────────────────────────────────

    fun connectToRoom(call: MethodCall, result: Result) {
        val accessToken = call.argument<String>("accessToken") ?: run {
            result.error("INVALID_ARG", "accessToken is required", null); return
        }
        val roomName = call.argument<String>("roomName") ?: run {
            result.error("INVALID_ARG", "roomName is required", null); return
        }
        val enableVideo = call.argument<Boolean>("enableVideo") ?: true
        val enableAudio = call.argument<Boolean>("enableAudio") ?: true

        // Disconnect any existing room first
        room?.disconnect()
        releaseLocalTracks()

        // Store result — will be resolved in onConnected or onConnectFailure
        pendingConnectResult = result
        pendingRoomName = roomName

        scope.launch(Dispatchers.IO) {
            try {
                if (enableAudio) {
                    localAudioTrack = LocalAudioTrack.create(context, true)
                }
                if (enableVideo) {
                    val cameraId = getCameraId(front = true)
                    if (cameraId != null && Camera2Capturer.isSupported(context)) {
                        cameraCapturer = Camera2Capturer(context, cameraId)
                        localVideoTrack = LocalVideoTrack.create(context, true, cameraCapturer!!)
                    }
                }

                val connectOptions = ConnectOptions.Builder(accessToken)
                    .roomName(roomName)
                    .apply {
                        localAudioTrack?.let { audioTracks(listOf(it)) }
                        localVideoTrack?.let { videoTracks(listOf(it)) }
                        enableNetworkQuality(true)
                        networkQualityConfiguration(
                            NetworkQualityConfiguration(
                                NetworkQualityVerbosity.NETWORK_QUALITY_VERBOSITY_MINIMAL,
                                NetworkQualityVerbosity.NETWORK_QUALITY_VERBOSITY_MINIMAL
                            )
                        )
                    }
                    .build()

                withContext(Dispatchers.Main) {
                    // Video.connect() is async — result resolved in roomListener.onConnected
                    room = Video.connect(context, connectOptions, roomListener)
                    TwilioLogger.debug("Video.connect() called for room: $roomName")
                }
            } catch (e: Exception) {
                TwilioLogger.error("connectToRoom setup failed", e)
                withContext(Dispatchers.Main) {
                    pendingConnectResult?.error("VIDEO_ERROR", e.message, null)
                    pendingConnectResult = null
                }
            }
        }
    }

    fun disconnectFromRoom(call: MethodCall, result: Result) {
        room?.disconnect()
        room = null
        releaseLocalTracks()
        result.success(null)
    }

    fun muteVideo(call: MethodCall, result: Result) {
        val muted = call.argument<Boolean>("muted") ?: false
        localVideoTrack?.enable(!muted)
        result.success(null)
    }

    fun muteAudio(call: MethodCall, result: Result) {
        val muted = call.argument<Boolean>("muted") ?: false
        localAudioTrack?.enable(!muted)
        result.success(null)
    }

    fun switchCamera(result: Result) {
        isFrontCamera = !isFrontCamera
        val cameraId = getCameraId(front = isFrontCamera)
        if (cameraId != null) {
            cameraCapturer?.switchCamera(cameraId)
        }
        result.success(null)
    }

    fun getParticipants(call: MethodCall, result: Result) {
        val currentRoom = room
        if (currentRoom == null) {
            result.success(emptyList<Map<String, Any>>())
            return
        }
        val participants = currentRoom.remoteParticipants.map { participant ->
            mapOf(
                "sid" to participant.sid,
                "identity" to participant.identity,
                "isVideoEnabled" to (participant.remoteVideoTracks.firstOrNull()?.isTrackEnabled ?: false),
                "isAudioEnabled" to (participant.remoteAudioTracks.firstOrNull()?.isTrackEnabled ?: false),
                "networkQualityLevel" to (participant.networkQualityLevel?.ordinal ?: 0),
                "isDominantSpeaker" to false
            )
        }
        TwilioLogger.debug("getParticipants: ${participants.size} participants in room")
        result.success(participants)
    }

    fun dispose() {
        room?.disconnect()
        releaseLocalTracks()
    }

    // ─── Room Listener ───────────────────────────────────────────────────────

    private val roomListener = object : Room.Listener {
        override fun onConnected(room: Room) {
            TwilioLogger.debug("Room connected: ${room.name} sid=${room.sid}")
            this@TwilioVideoManager.room = room

            // Reply to Flutter's connectToRoom() call now that we have the real SID
            pendingConnectResult?.success(
                mapOf(
                    "sid" to room.sid,
                    "name" to room.name,
                    "state" to "connected",
                    "localParticipantSid" to (room.localParticipant?.sid ?: "")
                )
            )
            pendingConnectResult = null

            // Emit roomConnected event so Flutter UI can react
            eventSink.send(mapOf(
                "type" to "roomConnected",
                "roomSid" to room.sid,
                "roomName" to room.name
            ))

            // Emit already-present participants (joined before us)
            room.remoteParticipants.forEach { participant ->
                TwilioLogger.debug("Existing participant in room: ${participant.identity}")
                eventSink.send(mapOf(
                    "type" to "participantConnected",
                    "participant" to mapOf(
                        "sid" to participant.sid,
                        "identity" to participant.identity,
                        "isVideoEnabled" to (participant.remoteVideoTracks.firstOrNull()?.isTrackEnabled ?: false),
                        "isAudioEnabled" to (participant.remoteAudioTracks.firstOrNull()?.isTrackEnabled ?: false),
                        "networkQualityLevel" to 0,
                        "isDominantSpeaker" to false
                    )
                ))
            }
        }

        override fun onConnectFailure(room: Room, twilioException: TwilioException) {
            TwilioLogger.error("Room connect failure: ${twilioException.message}", twilioException)
            pendingConnectResult?.error("VIDEO_ERROR", twilioException.message, null)
            pendingConnectResult = null
            eventSink.send(mapOf(
                "type" to "error",
                "message" to (twilioException.message ?: "Connect failed"),
                "code" to twilioException.code
            ))
        }

        override fun onDisconnected(room: Room, twilioException: TwilioException?) {
            TwilioLogger.debug("Room disconnected: ${room.name}")
            eventSink.send(mapOf(
                "type" to "roomDisconnected",
                "roomSid" to room.sid,
                "reason" to twilioException?.message
            ))
        }

        override fun onReconnecting(room: Room, twilioException: TwilioException) {
            eventSink.send(mapOf("type" to "roomReconnecting", "roomSid" to room.sid))
        }

        override fun onReconnected(room: Room) {
            eventSink.send(mapOf("type" to "roomReconnected", "roomSid" to room.sid))
        }

        override fun onParticipantConnected(room: Room, remoteParticipant: RemoteParticipant) {
            TwilioLogger.debug("Participant connected: ${remoteParticipant.identity}")
            eventSink.send(mapOf(
                "type" to "participantConnected",
                "participant" to mapOf(
                    "sid" to remoteParticipant.sid,
                    "identity" to remoteParticipant.identity,
                    "isVideoEnabled" to (remoteParticipant.remoteVideoTracks.firstOrNull()?.isTrackEnabled ?: false),
                    "isAudioEnabled" to (remoteParticipant.remoteAudioTracks.firstOrNull()?.isTrackEnabled ?: false),
                    "networkQualityLevel" to 0,
                    "isDominantSpeaker" to false
                )
            ))
        }

        override fun onParticipantDisconnected(room: Room, remoteParticipant: RemoteParticipant) {
            TwilioLogger.debug("Participant disconnected: ${remoteParticipant.identity}")
            eventSink.send(mapOf(
                "type" to "participantDisconnected",
                "participantSid" to remoteParticipant.sid
            ))
        }

        override fun onDominantSpeakerChanged(room: Room, remoteParticipant: RemoteParticipant?) {
            eventSink.send(mapOf(
                "type" to "dominantSpeakerChanged",
                "participantSid" to remoteParticipant?.sid
            ))
        }

        override fun onRecordingStarted(room: Room) {}
        override fun onRecordingStopped(room: Room) {}
    }

    // ─── Helpers ─────────────────────────────────────────────────────────────

    private fun releaseLocalTracks() {
        localAudioTrack?.release()
        localVideoTrack?.release()
        localAudioTrack = null
        localVideoTrack = null
        cameraCapturer = null
    }
}

package com.twiliocommkit.android.video

import android.content.Context
import android.hardware.camera2.CameraCharacteristics
import android.hardware.camera2.CameraManager
import android.media.AudioAttributes
import android.media.AudioFocusRequest
import android.media.AudioManager
import android.os.Build
import com.twilio.video.*
import com.twiliocommkit.android.TwilioLogger
import com.twiliocommkit.android.core.TwilioEventSink
import io.flutter.plugin.common.MethodCall
import io.flutter.plugin.common.MethodChannel.Result
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext

class TwilioVideoManager(
    private val context: Context,
    private val eventSink: TwilioEventSink,
    private val scope: CoroutineScope
) {

    private var room: Room? = null
    private var localAudioTrack: LocalAudioTrack? = null
    private var localVideoTrack: LocalVideoTrack? = null
    private var cameraCapturer: Camera2Capturer? = null
    private var isFrontCamera = true

    private var pendingConnectResult: Result? = null
    private var pendingRoomName: String = ""

    private var roomType: String = "group"
    private var enableNetworkQuality: Boolean = true
    private var preferredVideoCodec: String = "vp8"
    private var maxVideoBitrate: Int? = null
    private var maxAudioBitrate: Int? = null

    private val audioManager = context.getSystemService(Context.AUDIO_SERVICE) as AudioManager
    private var audioFocusRequest: AudioFocusRequest? = null

    // ─── Camera helpers ──────────────────────────────────────────────────────

    private fun getCameraId(front: Boolean): String? {
        val cameraManager = context.getSystemService(Context.CAMERA_SERVICE) as CameraManager
        for (id in cameraManager.cameraIdList) {
            val facing = cameraManager
                .getCameraCharacteristics(id)
                .get(CameraCharacteristics.LENS_FACING)
            val match = if (front)
                facing == CameraCharacteristics.LENS_FACING_FRONT
            else
                facing == CameraCharacteristics.LENS_FACING_BACK
            if (match) return id
        }
        return cameraManager.cameraIdList.firstOrNull()
    }

    // ─── Audio focus ──────────────────────────────────────────────────────────

    private fun requestAudioFocus() {
        audioManager.mode = AudioManager.MODE_IN_COMMUNICATION
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val req = AudioFocusRequest.Builder(AudioManager.AUDIOFOCUS_GAIN)
                .setAudioAttributes(
                    AudioAttributes.Builder()
                        .setUsage(AudioAttributes.USAGE_VOICE_COMMUNICATION)
                        .setContentType(AudioAttributes.CONTENT_TYPE_SPEECH)
                        .build()
                )
                .setAcceptsDelayedFocusGain(false)
                .build()
            audioFocusRequest = req
            audioManager.requestAudioFocus(req)
        } else {
            @Suppress("DEPRECATION")
            audioManager.requestAudioFocus(null, AudioManager.STREAM_VOICE_CALL, AudioManager.AUDIOFOCUS_GAIN)
        }
    }

    private fun abandonAudioFocus() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            audioFocusRequest?.let { audioManager.abandonAudioFocusRequest(it) }
            audioFocusRequest = null
        } else {
            @Suppress("DEPRECATION")
            audioManager.abandonAudioFocus(null)
        }
        audioManager.mode = AudioManager.MODE_NORMAL
    }

    // ─── Config ───────────────────────────────────────────────────────────────

    fun applyConfig(config: Map<String, Any?>) {
        roomType = config["roomType"] as? String ?: "group"
        enableNetworkQuality = config["enableNetworkQuality"] as? Boolean ?: true
        preferredVideoCodec = config["preferredVideoCodec"] as? String ?: "vp8"
        maxVideoBitrate = config["maxVideoBitrate"] as? Int
        maxAudioBitrate = config["maxAudioBitrate"] as? Int
        TwilioLogger.debug("VideoManager config applied: roomType=$roomType codec=$preferredVideoCodec")
    }

    // ─── Public API ──────────────────────────────────────────────────────────

    fun connectToRoom(call: MethodCall, result: Result) {
        val accessToken = call.argument<String>("accessToken") ?: run {
            result.error("INVALID_ARG", "accessToken is required", null); return
        }
        val roomName = call.argument<String>("roomName") ?: run {
            result.error("INVALID_ARG", "roomName is required", null); return
        }
        val enableVideo = call.argument<Boolean>("enableVideo") ?: true
        val enableAudio = call.argument<Boolean>("enableAudio") ?: true

        room?.disconnect()
        releaseLocalTracks()
        abandonAudioFocus()

        pendingConnectResult = result
        pendingRoomName = roomName

        // All Twilio SDK operations MUST run on Main thread
        scope.launch(Dispatchers.Main) {
            try {
                requestAudioFocus()

                if (enableAudio) {
                    localAudioTrack = LocalAudioTrack.create(context, true)
                    if (localAudioTrack == null) {
                        TwilioLogger.error("Failed to create LocalAudioTrack — check RECORD_AUDIO permission")
                    } else {
                        TwilioLogger.debug("LocalAudioTrack created: enabled=${localAudioTrack!!.isEnabled}")
                    }
                }

                if (enableVideo) {
                    val cameraId = getCameraId(front = true)
                    TwilioLogger.debug("Camera ID for front: $cameraId, Camera2Capturer supported: ${Camera2Capturer.isSupported(context)}")
                    if (cameraId != null && Camera2Capturer.isSupported(context)) {
                        cameraCapturer = Camera2Capturer(context, cameraId)
                        localVideoTrack = LocalVideoTrack.create(context, true, cameraCapturer!!)
                        if (localVideoTrack == null) {
                            TwilioLogger.error("Failed to create LocalVideoTrack — check CAMERA permission")
                        } else {
                            TwilioLogger.debug("LocalVideoTrack created: enabled=${localVideoTrack!!.isEnabled}")
                        }
                    }
                }

                val connectOptionsBuilder = ConnectOptions.Builder(accessToken)
                    .roomName(roomName)

                localAudioTrack?.let {
                    connectOptionsBuilder.audioTracks(listOf(it))
                    TwilioLogger.debug("Adding audio track to connect options")
                }
                localVideoTrack?.let {
                    connectOptionsBuilder.videoTracks(listOf(it))
                    TwilioLogger.debug("Adding video track to connect options")
                }

                connectOptionsBuilder.enableNetworkQuality(true)
                connectOptionsBuilder.networkQualityConfiguration(
                    NetworkQualityConfiguration(
                        NetworkQualityVerbosity.NETWORK_QUALITY_VERBOSITY_MINIMAL,
                        NetworkQualityVerbosity.NETWORK_QUALITY_VERBOSITY_MINIMAL
                    )
                )

                val connectOptions = connectOptionsBuilder.build()
                room = Video.connect(context, connectOptions, roomListener)
                TwilioLogger.debug("Video.connect() called for room: $roomName")

            } catch (e: Exception) {
                TwilioLogger.error("connectToRoom setup failed", e)
                pendingConnectResult?.error("VIDEO_ERROR", e.message, null)
                pendingConnectResult = null
            }
        }
    }

    fun disconnectFromRoom(call: MethodCall, result: Result) {
        room?.disconnect()
        room = null
        releaseLocalTracks()
        abandonAudioFocus()
        result.success(null)
    }

    fun muteVideo(call: MethodCall, result: Result) {
        val muted = call.argument<Boolean>("muted") ?: false
        localVideoTrack?.enable(!muted)
        TwilioLogger.debug("Video ${if (muted) "muted" else "unmuted"}")
        result.success(null)
    }

    fun muteAudio(call: MethodCall, result: Result) {
        val muted = call.argument<Boolean>("muted") ?: false
        localAudioTrack?.enable(!muted)
        TwilioLogger.debug("Audio ${if (muted) "muted" else "unmuted"}")
        result.success(null)
    }

    fun switchCamera(result: Result) {
        isFrontCamera = !isFrontCamera
        val cameraId = getCameraId(front = isFrontCamera)
        if (cameraId != null) {
            cameraCapturer?.switchCamera(cameraId)
            TwilioLogger.debug("Switched to ${if (isFrontCamera) "front" else "back"} camera: $cameraId")
        }
        result.success(null)
    }

    fun getParticipants(call: MethodCall, result: Result) {
        val currentRoom = room
        if (currentRoom == null) {
            result.success(emptyList<Map<String, Any>>())
            return
        }
        val participants = currentRoom.remoteParticipants.map { participant ->
            mapOf(
                "sid" to participant.sid,
                "identity" to participant.identity,
                "isVideoEnabled" to (participant.remoteVideoTracks.firstOrNull()?.isTrackEnabled ?: false),
                "isAudioEnabled" to (participant.remoteAudioTracks.firstOrNull()?.isTrackEnabled ?: false),
                "networkQualityLevel" to (participant.networkQualityLevel?.ordinal ?: 0),
                "isDominantSpeaker" to false
            )
        }
        TwilioLogger.debug("getParticipants: ${participants.size} in room")
        result.success(participants)
    }

    fun dispose() {
        room?.disconnect()
        releaseLocalTracks()
        abandonAudioFocus()
    }

    // ─── Room Listener ───────────────────────────────────────────────────────

    private val roomListener = object : Room.Listener {
        override fun onConnected(room: Room) {
            TwilioLogger.debug("Room connected: ${room.name} sid=${room.sid} participants=${room.remoteParticipants.size}")
            this@TwilioVideoManager.room = room

            pendingConnectResult?.success(
                mapOf(
                    "sid" to room.sid,
                    "name" to room.name,
                    "state" to "connected",
                    "localParticipantSid" to (room.localParticipant?.sid ?: "")
                )
            )
            pendingConnectResult = null

            eventSink.send(mapOf(
                "type" to "roomConnected",
                "roomSid" to room.sid,
                "roomName" to room.name
            ))

            // Emit participants already in the room
            room.remoteParticipants.forEach { participant ->
                TwilioLogger.debug("Pre-existing participant: ${participant.identity}")
                eventSink.send(mapOf(
                    "type" to "participantConnected",
                    "participant" to mapOf(
                        "sid" to participant.sid,
                        "identity" to participant.identity,
                        "isVideoEnabled" to (participant.remoteVideoTracks.firstOrNull()?.isTrackEnabled ?: false),
                        "isAudioEnabled" to (participant.remoteAudioTracks.firstOrNull()?.isTrackEnabled ?: false),
                        "networkQualityLevel" to 0,
                        "isDominantSpeaker" to false
                    )
                ))
            }
        }

        override fun onConnectFailure(room: Room, twilioException: TwilioException) {
            TwilioLogger.error("Room connect failure: ${twilioException.message}", twilioException)
            pendingConnectResult?.error("VIDEO_ERROR", twilioException.message, null)
            pendingConnectResult = null
            eventSink.send(mapOf("type" to "error",
                "message" to (twilioException.message ?: "Connect failed"),
                "code" to twilioException.code))
        }

        override fun onDisconnected(room: Room, twilioException: TwilioException?) {
            TwilioLogger.debug("Room disconnected: ${room.name}")
            abandonAudioFocus()
            eventSink.send(mapOf("type" to "roomDisconnected",
                "roomSid" to room.sid, "reason" to twilioException?.message))
        }

        override fun onReconnecting(room: Room, twilioException: TwilioException) {
            eventSink.send(mapOf("type" to "roomReconnecting", "roomSid" to room.sid))
        }

        override fun onReconnected(room: Room) {
            eventSink.send(mapOf("type" to "roomReconnected", "roomSid" to room.sid))
        }

        override fun onParticipantConnected(room: Room, remoteParticipant: RemoteParticipant) {
            TwilioLogger.debug("Participant connected: ${remoteParticipant.identity}")
            eventSink.send(mapOf(
                "type" to "participantConnected",
                "participant" to mapOf(
                    "sid" to remoteParticipant.sid,
                    "identity" to remoteParticipant.identity,
                    "isVideoEnabled" to (remoteParticipant.remoteVideoTracks.firstOrNull()?.isTrackEnabled ?: false),
                    "isAudioEnabled" to (remoteParticipant.remoteAudioTracks.firstOrNull()?.isTrackEnabled ?: false),
                    "networkQualityLevel" to 0,
                    "isDominantSpeaker" to false
                )
            ))
        }

        override fun onParticipantDisconnected(room: Room, remoteParticipant: RemoteParticipant) {
            TwilioLogger.debug("Participant disconnected: ${remoteParticipant.identity}")
            eventSink.send(mapOf("type" to "participantDisconnected",
                "participantSid" to remoteParticipant.sid))
        }

        override fun onDominantSpeakerChanged(room: Room, remoteParticipant: RemoteParticipant?) {
            eventSink.send(mapOf("type" to "dominantSpeakerChanged",
                "participantSid" to remoteParticipant?.sid))
        }

        override fun onRecordingStarted(room: Room) {}
        override fun onRecordingStopped(room: Room) {}
    }

    // ─── Helpers ─────────────────────────────────────────────────────────────

    private fun releaseLocalTracks() {
        localAudioTrack?.release()
        localVideoTrack?.release()
        localAudioTrack = null
        localVideoTrack = null
        cameraCapturer = null
    }
}

