import 'dart:async';

import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:flutter_twilio_commkit/flutter_twilio_commkit.dart';

import 'config/twilio_app_config.dart';
import 'screens/settings_screen.dart';
import 'screens/video_test_screen.dart';
import 'screens/voice_test_screen.dart';
import 'services/notification_service.dart';
import 'services/twilio_token_service.dart';

/// Method channel that talks to MainActivity.kt to retrieve the pending
/// incoming call intent (set when app was launched from IncomingCallActivity).
const _kIncomingCallChannel =
    MethodChannel('com.twiliocommkit/incoming_call');

void main() async {
  WidgetsFlutterBinding.ensureInitialized();

  // Load persisted settings
  await AppSettings.load();

  // Initialise Firebase + FCM push notifications
  try {
    await NotificationService.instance.initialise();
  } catch (e) {
    debugPrint('[main] Firebase/notification init failed: $e\n'
        '  → Run `flutterfire configure` and add google-services.json\n'
        '  → See notification_service.dart for setup instructions');
  }

  // Initialize the Twilio SDK
  await TwilioCommKit.initialize(
    config: TwilioCommKitConfig(
      credentials: TwilioCredentials(
        accountSid: TwilioAppConfig.accountSid,
        apiKeySid: TwilioAppConfig.apiKeySid,
        outgoingApplicationSid: TwilioAppConfig.outgoingApplicationSid,
        pushCredentialSid: TwilioAppConfig.pushCredentialSid,
      ),
      accessTokenProvider: TwilioTokenService.instance.fetchToken,
      videoConfig: const TwilioVideoConfig(
        roomType: TwilioRoomType.group,
        enableNetworkQuality: true,
        enableDominantSpeaker: true,
        preferredVideoCodec: TwilioVideoCodec.vp8,
      ),
      voiceConfig: TwilioVoiceConfig(
        callerIdName: TwilioAppConfig.userIdentity,
        enableCallKit: true,
        enableForegroundService: true,
        enableInsights: true,
      ),
      logLevel: TwilioLogLevel.debug,
    ),
  );

  runApp(const ProviderScope(child: AdvancedExampleApp()));
}

class AdvancedExampleApp extends StatelessWidget {
  const AdvancedExampleApp({super.key});

  @override
  Widget build(BuildContext context) {
    return TwilioTheme(
      data: TwilioThemeData.dark(),
      child: MaterialApp(
        title: 'Twilio CommKit — Advanced',
        debugShowCheckedModeBanner: false,
        darkTheme: ThemeData.dark(useMaterial3: true).copyWith(
          colorScheme: ColorScheme.fromSeed(
            seedColor: const Color(0xFF1A0533),
            brightness: Brightness.dark,
          ),
        ),
        themeMode: ThemeMode.dark,
        home: const _AdvancedHomeScreen(),
      ),
    );
  }
}

class _AdvancedHomeScreen extends StatefulWidget {
  const _AdvancedHomeScreen();

  @override
  State<_AdvancedHomeScreen> createState() => _AdvancedHomeScreenState();
}

class _AdvancedHomeScreenState extends State<_AdvancedHomeScreen> {
  StreamSubscription<Map<String, dynamic>>? _callSub;
  StreamSubscription<IncomingCallEvent>? _voiceCallSub;
  StreamSubscription<String>? _fcmTokenSub;
  String? _fcmToken;
  String? _activeIncomingCallSid; // guard against duplicate events

  @override
  void initState() {
    super.initState();

    _fcmTokenSub = NotificationService.instance.onFcmToken.listen((token) {
      if (mounted) setState(() => _fcmToken = token);
    });
    _fcmToken = NotificationService.instance.currentFcmToken;

    // Listen to FCM notification-based incoming calls
    _callSub = NotificationService.instance.onIncomingCall.listen((payload) {
      if (!mounted) return;
      _handleIncomingCallPayload(payload);
    });

    // Also listen to Voice SDK incoming calls (e.g. when app is in foreground)
    _voiceCallSub = TwilioVoice.instance.onIncomingCall.listen((event) {
      if (!mounted) return;
      _handleIncomingCallPayload({
        'callSid': event.callSid,
        'from': event.from ?? 'Unknown',
      });
    });

    // Check if app was launched from IncomingCallActivity (killed app scenario)
    WidgetsBinding.instance.addPostFrameCallback((_) => _checkPendingCallIntent());
  }

  /// Called once after first frame — reads any pending call from native side.
  Future<void> _checkPendingCallIntent() async {
    try {
      final result = await _kIncomingCallChannel
          .invokeMapMethod<String, dynamic>('getPendingIncomingCall');
      if (result == null || !mounted) return;

      final callSid = result['callSid'] as String? ?? '';
      final from = (result['from'] as String? ?? 'Unknown').replaceFirst('client:', '');
      final accepted = result['accepted'] as bool? ?? false;

      if (callSid.isEmpty) return;
      _activeIncomingCallSid = callSid; // mark as active

      if (accepted) {
        // User already tapped Accept on IncomingCallActivity — go straight to call screen
        NotificationService.instance.dismissIncomingCallNotification();
        // Initialize voice SDK first if needed, then accept
        await _initVoiceIfNeededAndAccept(callSid: callSid, from: from);
      } else {
        // User tapped the notification banner (not the Accept button)
        _activeIncomingCallSid = null;
        _handleIncomingCallPayload({'callSid': callSid, 'from': from});
      }
    } catch (_) {
      // Not Android or method not available — ignore
    }
  }

  Future<void> _initVoiceIfNeededAndAccept({
    required String callSid,
    required String from,
  }) async {
    try {
      final result = await TwilioTokenService.instance.fetchVoiceToken();
      if (!mounted) return;
      if (result is TokenSuccess) {
        final fcmToken = NotificationService.instance.currentFcmToken;
        await TwilioVoice.instance.initialize(
          accessToken: result.token,
          fcmToken: fcmToken,
        );
        await TwilioVoice.instance.acceptCall(callSid: callSid);
        if (!mounted) return;
        Navigator.push(
          context,
          MaterialPageRoute(
            builder: (_) => TwilioVoiceCallScreen(
              callSid: callSid,
              remoteIdentity: from,
              theme: TwilioThemeData.dark(),
              onCallEnded: () => Navigator.pop(context),
            ),
          ),
        );
      }
    } catch (e) {
      debugPrint('[main] Failed to accept call from killed state: $e');
    }
  }

  @override
  void dispose() {
    _callSub?.cancel();
    _voiceCallSub?.cancel();
    _fcmTokenSub?.cancel();
    super.dispose();
  }

  void _handleIncomingCallPayload(Map<String, dynamic> payload) {
    final callSid = payload['callSid'] as String? ?? '';
    final from = (payload['from'] as String? ?? 'Unknown')
        .replaceFirst('client:', '');
    if (callSid.isEmpty) return;

    // Deduplicate: ignore if we're already handling this call
    if (_activeIncomingCallSid == callSid) return;
    _activeIncomingCallSid = callSid;

    showModalBottomSheet(
      context: context,
      isDismissible: false,
      isScrollControlled: true,
      builder: (_) => TwilioIncomingCallScreen(
        callSid: callSid,
        from: from,
        theme: TwilioThemeData.dark(),
        onAccepted: () {
          NotificationService.instance.dismissIncomingCallNotification();
          _activeIncomingCallSid = null;
          Navigator.pop(context);
          Navigator.push(
            context,
            MaterialPageRoute(
              builder: (_) => TwilioVoiceCallScreen(
                callSid: callSid,
                remoteIdentity: from,
                theme: TwilioThemeData.dark(),
                onCallEnded: () => Navigator.pop(context),
              ),
            ),
          );
        },
        onRejected: () {
          NotificationService.instance.dismissIncomingCallNotification();
          _activeIncomingCallSid = null;
          Navigator.pop(context);
        },
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Twilio CommKit — Advanced'),
        actions: [
          IconButton(
            icon: const Icon(Icons.settings),
            tooltip: 'Configure server URL & identity',
            onPressed: () => Navigator.push(
              context,
              MaterialPageRoute(builder: (_) => const SettingsScreen()),
            ),
          ),
        ],
      ),
      body: ListView(
        padding: const EdgeInsets.all(24),
        children: [
          _ServerStatusCard(),
          const SizedBox(height: 12),
          _FcmTokenCard(token: _fcmToken),
          const SizedBox(height: 24),
          const Text('Features',
              style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
          const SizedBox(height: 12),
          _FeatureTile(
            icon: Icons.videocam,
            color: const Color(0xFF1A0533),
            title: 'Custom Video Call UI',
            subtitle: 'Themed video call with custom controls & participant tiles\n'
                'Tests: connect, mute, camera switch, participants',
            onTap: () => Navigator.push(
              context,
              MaterialPageRoute(builder: (_) => const VideoTestScreen()),
            ),
          ),
          const SizedBox(height: 12),
          _FeatureTile(
            icon: Icons.call,
            color: const Color(0xFF0D2B0D),
            title: 'Voice Call',
            subtitle:
                'Fetch token → Initialize Voice SDK → Make / Receive calls\n'
                'Tests: outgoing, incoming (FCM push), mute, hold, speaker',
            onTap: () => Navigator.push(
              context,
              MaterialPageRoute(builder: (_) => const VoiceTestScreen()),
            ),
          ),
          const SizedBox(height: 24),
          _ThemeSwitcher(),
          const SizedBox(height: 16),
          _QuickHelp(),
        ],
      ),
    );
  }
}

