class _ServerStatusCardState extends State<_ServerStatusCard> {
  String _status = 'Not tested';
  bool _testing = false;
  Color _color = Colors.grey;

  @override
  Widget build(BuildContext context) {
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(children: [
          Row(children: [
