                      style: const TextStyle(
                          fontFamily: 'monospace',
                          fontSize: 12,
                          color: Colors.grey),
                    ),
                  ]),
            ),
            TextButton(
              onPressed: _testing ? null : _pingServer,
              child: _testing
                  ? const SizedBox.square(
                      dimension: 16,
                      child: CircularProgressIndicator(strokeWidth: 2))
                  : const Text('Ping'),
            ),
          ]),
          if (_status != 'Not tested') ...[
            const SizedBox(height: 8),
            Row(children: [
              Icon(
                _color == Colors.green ? Icons.check_circle : Icons.cancel,
                color: _color,
                size: 16,
              ),
              const SizedBox(width: 6),
              Expanded(
                child: Text(_status,
                    style: TextStyle(color: _color, fontSize: 12)),
              ),
            ]),
          ],
          const SizedBox(height: 4),
          Align(
            alignment: Alignment.centerLeft,
            child: TextButton.icon(
              icon: const Icon(Icons.settings, size: 14),
              label: const Text('Change server URL',
                  style: TextStyle(fontSize: 12)),
              onPressed: () async {
                await Navigator.push(
                  context,
                  MaterialPageRoute(
                      builder: (_) => const SettingsScreen()),
                );
                setState(() {});
              },
            ),
          ),
        ]),
      ),
    );
  }

  Future<void> _pingServer() async {
    setState(() {
      _testing = true;
      _status = 'Testing…';
      _color = Colors.grey;
    });
    final result = await TwilioTokenService.instance
        .fetchVideoToken(roomName: 'ping-test');
    if (!mounted) return;
    setState(() {
      _testing = false;
      switch (result) {
        case TokenSuccess():
          _status = '✓ Server reachable — token received';
          _color = Colors.green;
        case TokenFailure(:final message):
          _status = message.split('\n').first;
          _color = Colors.red;
      }
    });
  }
}

