  process.exit(1);
}

const {
  TWILIO_ACCOUNT_SID,
  TWILIO_API_KEY_SID,
  TWILIO_API_KEY_SECRET,
  TWILIO_TWIML_APP_SID,
  TWILIO_PUSH_CREDENTIAL_SID,   // ← FCM Push Credential SID (CR...)
  TWILIO_CALLER_ID,
  PORT = 3000,
  TOKEN_TTL = 3600,
} = process.env;

// ── App ──────────────────────────────────────────────────────────────────────

const app = express();
app.use(cors());
app.use(express.json());
app.use(express.urlencoded({ extended: false }));

// ── Health check ─────────────────────────────────────────────────────────────

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', accountSid: TWILIO_ACCOUNT_SID, time: new Date().toISOString() });
});

// ── Token endpoint ────────────────────────────────────────────────────────────
//
// Query params (GET) or body params (POST):
//   type      "video" | "voice"       (default: "video")
//   identity  participant identity    (default: "flutter-user")
//   room      video room name         (required for video)

app.all('/token', (req, res) => {
  const params   = { ...req.query, ...req.body };
  const type     = (params.type     || 'video').toLowerCase();
  const identity = (params.identity || 'flutter-user').trim();
  const room     = (params.room     || '').trim();

  if (!identity) return res.status(400).json({ error: 'identity is required' });

  try {
    const token = new AccessToken(
      TWILIO_ACCOUNT_SID, TWILIO_API_KEY_SID, TWILIO_API_KEY_SECRET,
      { identity, ttl: Number(TOKEN_TTL) }
    );

    if (type === 'video') {
      if (!room) return res.status(400).json({ error: 'room is required for type=video' });
      token.addGrant(new VideoGrant({ room }));
      console.log(`[${new Date().toISOString()}] VIDEO | identity=${identity} room=${room}`);

    } else if (type === 'voice') {
      token.addGrant(new VoiceGrant({
        outgoingApplicationSid: TWILIO_TWIML_APP_SID || undefined,
        incomingAllow: true,
        // CRITICAL: pushCredentialSid tells Twilio which FCM credential to use
        // to send push notifications to this device for incoming calls.
        // Must be set to the FCM Push Credential SID (CR...) from Twilio Console.
        pushCredentialSid: TWILIO_PUSH_CREDENTIAL_SID || undefined,
      }));
      console.log(`[${new Date().toISOString()}] VOICE | identity=${identity} pushCred=${TWILIO_PUSH_CREDENTIAL_SID ? 'set' : '⚠️  NOT SET — incoming calls will fail!'}`);


    } else {
      return res.status(400).json({ error: `Unknown type "${type}". Use "video" or "voice".` });
    }

    return res.json({ token: token.toJwt() });
  } catch (err) {
    console.error('Token error:', err);
    return res.status(500).json({ error: err.message });
  }
});

// ── Voice TwiML handler ───────────────────────────────────────────────────────
// Called by Twilio when an outgoing call is placed.
// Set TwiML App → Voice URL to: https://<your-render-app>.onrender.com/voice
//
// Handles BOTH GET and POST — Twilio console lets you choose either method.
// If you get HTTP 404, make sure the TwiML App Voice URL points here.

app.all('/voice', (req, res) => {
  // Twilio sends params in body (POST) or query string (GET)
  const params = { ...req.query, ...req.body };
  const to   = params.To   || params.to   || '';
  const from = params.From || params.from || params.Caller || 'unknown';

  console.log(`[${new Date().toISOString()}] TWIML | method=${req.method} from=${from} to=${to}`);
  res.set('Content-Type', 'text/xml');

  if (!to) {
    // No "To" param — just acknowledge
    return res.send(`<Response><Say>No destination specified.</Say><Hangup/></Response>`);
  }

  // Phone number → dial directly
  if (to.startsWith('+') || to.startsWith('00')) {
    const callerId = TWILIO_CALLER_ID || from;
    return res.send(
      `<Response>` +
      `<Dial callerId="${callerId}" timeout="30" answerOnBridge="true">` +
      `<Number>${to}</Number>` +
      `</Dial>` +
      `</Response>`
    );
  }

  // Twilio Client identity → dial client app
  // answerOnBridge="true"  → caller hears ringing until receiver picks up
  // timeout="30"           → ring for 30 seconds before giving up
  const clientId = to.replace('client:', '');
  return res.send(
    `<Response>` +
    `<Dial answerOnBridge="true" timeout="30">` +
    `<Client>${clientId}</Client>` +
    `</Dial>` +
    `</Response>`
  );
});

// ── 404 ──────────────────────────────────────────────────────────────────────

app.use((req, res) => {
  res.status(404).json({ error: `Not found: ${req.method} ${req.path}` });
});

// ── Start ─────────────────────────────────────────────────────────────────────

app.listen(PORT, () => {
  console.log(`\n  Twilio Token Server running on port ${PORT}`);
  console.log(`   Health:      http://localhost:${PORT}/health`);
  console.log(`   Video token: http://localhost:${PORT}/token?type=video&room=test&identity=user1`);
  console.log(`   Voice token: http://localhost:${PORT}/token?type=voice&identity=user1`);
  console.log(`   Voice TwiML: http://localhost:${PORT}/voice`);
  console.log(`\n   Render URL:  https://<your-app-name>.onrender.com`);
  console.log(`   Account SID: ${TWILIO_ACCOUNT_SID}`);
  console.log(`   TwiML App:   ${TWILIO_TWIML_APP_SID || '⚠️  NOT SET — voice calls will fail'}`);
  console.log(`   Push Cred:   ${TWILIO_PUSH_CREDENTIAL_SID || '⚠️  NOT SET — incoming calls will fail'}\n`);
});

import 'package:flutter/material.dart';
import 'package:flutter_twilio_commkit/flutter_twilio_commkit.dart';
import 'package:shared_preferences/shared_preferences.dart';

import '../services/twilio_token_service.dart';

const _keyServerUrl   = 'adv_token_server_url';
const _keyIdentity    = 'adv_user_identity';
const _keyRoomName    = 'adv_room_name';
const _keyCallTo      = 'adv_call_to';
const _keyAvatarImage = 'adv_avatar_image_url';

/// Persists and loads test settings using SharedPreferences.
class AppSettings {
  static late SharedPreferences _prefs;

  static Future<void> load() async {
    _prefs = await SharedPreferences.getInstance();
    TwilioTokenService.instance
        .setBaseUrl(_prefs.getString(_keyServerUrl) ??
            TwilioTokenService.instance.currentBaseUrl);
    TwilioTokenService.instance
        .setIdentity(_prefs.getString(_keyIdentity) ??
            TwilioTokenService.instance.currentIdentity);
    // Restore avatar image URL
    final imageUrl = _prefs.getString(_keyAvatarImage);
    TwilioUserPreferences.instance.avatarImageUrl = imageUrl;
  }

  static String get serverUrl =>
      _prefs.getString(_keyServerUrl) ??
      TwilioTokenService.instance.currentBaseUrl;

  static String get identity =>
      _prefs.getString(_keyIdentity) ??
      TwilioTokenService.instance.currentIdentity;

  static String get roomName =>
      _prefs.getString(_keyRoomName) ?? 'advanced-room-001';

  static String get callTo =>
      _prefs.getString(_keyCallTo) ?? 'flutter-tester-2';

  static Future<void> save({
    required String serverUrl,
    required String identity,
    required String roomName,
    required String callTo,
    String? avatarImageUrl,
  }) async {
    await Future.wait([
      _prefs.setString(_keyServerUrl, serverUrl),
      _prefs.setString(_keyIdentity,  identity),
      _prefs.setString(_keyRoomName,  roomName),
      _prefs.setString(_keyCallTo,    callTo),
      if (avatarImageUrl != null && avatarImageUrl.isNotEmpty)
        _prefs.setString(_keyAvatarImage, avatarImageUrl)
      else
        _prefs.remove(_keyAvatarImage),
    ]);
    TwilioTokenService.instance.setBaseUrl(serverUrl);
    TwilioTokenService.instance.setIdentity(identity);
    TwilioUserPreferences.instance
      ..avatarImageUrl = avatarImageUrl?.isNotEmpty == true ? avatarImageUrl : null;
    // Keep registry in sync with the local user's identity
    TwilioAvatarRegistry.instance.register(identity: identity, imageUrl: avatarImageUrl);
  }
}

/// Settings screen — configure token server, identity, avatar photo URL, and test values.
class SettingsScreen extends StatefulWidget {
  const SettingsScreen({super.key});

  @override
  State<SettingsScreen> createState() => _SettingsScreenState();
}

class _SettingsScreenState extends State<SettingsScreen> {
  final _formKey = GlobalKey<FormState>();
  late final TextEditingController _serverUrlCtrl;
  late final TextEditingController _identityCtrl;
  late final TextEditingController _roomCtrl;
  late final TextEditingController _callToCtrl;
  late final TextEditingController _avatarImageCtrl;
  bool _saving = false;

  @override
  void initState() {
    super.initState();
    _serverUrlCtrl   = TextEditingController(text: AppSettings.serverUrl);
    _identityCtrl    = TextEditingController(text: AppSettings.identity);
    _roomCtrl        = TextEditingController(text: AppSettings.roomName);
    _callToCtrl      = TextEditingController(text: AppSettings.callTo);
    _avatarImageCtrl = TextEditingController(
        text: TwilioUserPreferences.instance.avatarImageUrl ?? '');
  }

  @override
  void dispose() {
    _serverUrlCtrl.dispose();
    _identityCtrl.dispose();
    _roomCtrl.dispose();
    _callToCtrl.dispose();
    _avatarImageCtrl.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Settings'),
        actions: [
          IconButton(
            icon: const Icon(Icons.save),
            tooltip: 'Save',
            onPressed: _save,
          ),
        ],
      ),
      body: Form(
        key: _formKey,
        child: ListView(
          padding: const EdgeInsets.all(20),
          children: [
            // ── Avatar photo ──────────────────────────────────────────────
            _SectionHeader('Profile Picture'),
            const SizedBox(height: 8),
            _AvatarPreview(imageUrl: _avatarImageCtrl.text.trim()),
            const SizedBox(height: 14),
            _Field(
              controller: _avatarImageCtrl,
              label: 'Profile Picture URL',
              hint: 'https://example.com/photo.png',
              helper: 'Public image URL shown as your avatar in calls. '
                  'Leave blank for auto-generated avatar.',
              onChanged: (_) => setState(() {}),
            ),
            const Divider(height: 32),

            // ── Connection ─────────────────────────────────────────────────
            _SectionHeader('Token Server'),
            _Field(
              controller: _serverUrlCtrl,
              label: 'Token Server URL',
              hint: 'https://your-render-app.onrender.com',
              helper: 'Render deployed URL or http://10.0.2.2:3000 for emulator',
              validator: (v) =>
                  (v == null || v.trim().isEmpty) ? 'Required' : null,
            ),
            const SizedBox(height: 20),
            _SectionHeader('Identity'),
            _Field(
              controller: _identityCtrl,
              label: 'User Identity',
              hint: 'flutter-advanced-1',
              helper: 'Participant name in video/voice.',
              validator: (v) =>
                  (v == null || v.trim().isEmpty) ? 'Required' : null,
            ),
            const SizedBox(height: 20),
            _SectionHeader('Video'),
            _Field(
              controller: _roomCtrl,
              label: 'Room Name',
              hint: 'advanced-room-001',
              helper: 'Video room to join.',
            ),
            const SizedBox(height: 20),
            _SectionHeader('Voice'),
            _Field(
              controller: _callToCtrl,
              label: 'Call To (identity or E.164)',
              hint: 'flutter-tester-2',
              helper: 'Twilio client identity or phone number to call.',
            ),
            const SizedBox(height: 32),
            ElevatedButton.icon(
              icon: _saving
                  ? const SizedBox.square(
                      dimension: 18,
                      child: CircularProgressIndicator(strokeWidth: 2))
                  : const Icon(Icons.save),
              label: const Text('Save Settings'),
              onPressed: _saving ? null : _save,
            ),
            const SizedBox(height: 16),
            OutlinedButton.icon(
              icon: const Icon(Icons.network_ping),
              label: const Text('Test Server Connection'),
              onPressed: _testConnection,
            ),
          ],
        ),
      ),
    );
  }

  Future<void> _save() async {
    if (!_formKey.currentState!.validate()) return;
    setState(() => _saving = true);
    await AppSettings.save(
      serverUrl:      _serverUrlCtrl.text.trim(),
      identity:       _identityCtrl.text.trim(),
      roomName:       _roomCtrl.text.trim(),
      callTo:         _callToCtrl.text.trim(),
      avatarImageUrl: _avatarImageCtrl.text.trim(),
    );
    setState(() => _saving = false);
    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Settings saved ✓'),
          backgroundColor: Colors.green,
          duration: Duration(seconds: 2),
        ),
      );
    }
  }

  Future<void> _testConnection() async {
    ScaffoldMessenger.of(context).showSnackBar(
      const SnackBar(content: Text('Testing server connection…')),
    );
    final result = await TwilioTokenService.instance.fetchVideoToken(
      roomName: _roomCtrl.text.trim().isNotEmpty
          ? _roomCtrl.text.trim()
          : 'test-room',
      identity: _identityCtrl.text.trim(),
    );
    if (!mounted) return;
    ScaffoldMessenger.of(context).clearSnackBars();
    switch (result) {
      case TokenSuccess(:final token):
        final preview = token.length > 40
            ? '${token.substring(0, 40)}…'
            : token;
        _showDialog('✅ Connected!', 'Token received.\n\nPreview:\n$preview');
      case TokenFailure(:final message):
        _showDialog('❌ Connection Failed', message);
    }
  }

  void _showDialog(String title, String message) {
    showDialog(
      context: context,
      builder: (_) => AlertDialog(
        title: Text(title),
        content: SingleChildScrollView(child: Text(message)),
        actions: [
          TextButton(
              onPressed: () => Navigator.pop(context),
              child: const Text('OK')),
        ],
      ),
    );
  }
}

// ─── Avatar Preview ───────────────────────────────────────────────────────────

class _AvatarPreview extends StatelessWidget {
  const _AvatarPreview({required this.imageUrl});
  final String imageUrl;

  @override
  Widget build(BuildContext context) {
    const double r = 40;
    final bool hasImage = imageUrl.isNotEmpty;
    final bool isNetwork =
        imageUrl.startsWith('http://') || imageUrl.startsWith('https://');

    return Center(
      child: Column(
        children: [
          Container(
            width: r * 2,
            height: r * 2,
            decoration: BoxDecoration(
              shape: BoxShape.circle,
              color: Colors.grey.shade300,
            ),
            child: ClipOval(
              child: hasImage
                  ? Image(
                      image: isNetwork
                          ? NetworkImage(imageUrl) as ImageProvider
                          : AssetImage(imageUrl) as ImageProvider,
                      width: r * 2,
                      height: r * 2,
                      fit: BoxFit.cover,
                      errorBuilder: (_, __, ___) => const Icon(
                        Icons.broken_image,
                        size: 36,
                        color: Colors.grey,
                      ),
                    )
                  : const Icon(Icons.person, size: 44, color: Colors.grey),
            ),
          ),
          const SizedBox(height: 6),
          Text(
            hasImage ? 'Preview' : 'No image set — auto avatar will be used',
            style: TextStyle(fontSize: 12, color: Colors.grey[600]),
          ),
        ],
      ),
    );
  }
}

// ─── Reusable helpers ─────────────────────────────────────────────────────────

class _SectionHeader extends StatelessWidget {
  const _SectionHeader(this.title);
  final String title;
  @override
  Widget build(BuildContext context) {
    return Padding(
      padding: const EdgeInsets.only(bottom: 8),
      child: Text(title,
          style: TextStyle(
              fontWeight: FontWeight.bold,
              color: Theme.of(context).colorScheme.primary,
              fontSize: 14)),
    );
  }
}

class _Field extends StatelessWidget {
  const _Field({
    required this.controller,
    required this.label,
    required this.hint,
    this.helper,
    this.validator,
    this.onChanged,
  });

  final TextEditingController controller;
  final String label;
  final String hint;
  final String? helper;
  final String? Function(String?)? validator;
  final void Function(String)? onChanged;

  @override
  Widget build(BuildContext context) {
    return TextFormField(
      controller: controller,
      validator: validator,
      onChanged: onChanged,
      decoration: InputDecoration(
        labelText: label,
        hintText: hint,
        helperText: helper,
        helperMaxLines: 2,
        border: const OutlineInputBorder(),
        contentPadding:
            const EdgeInsets.symmetric(horizontal: 12, vertical: 12),
      ),
    );
  }
}

