import 'package:flutter/material.dart';

/// Builds a circular network-image avatar for [identity].
///
/// Loads `https://i.pravatar.cc/150?u=<identity>` by default.
/// Callers may supply an explicit [imageUrl] to override.
/// Falls back to a coloured circle with a person icon on error.
Widget buildIdentityAvatar({
  required String identity,
  double size = 80,
  String? imageUrl,
}) {
  final url = (imageUrl != null && imageUrl.isNotEmpty)
      ? imageUrl
      : 'https://i.pravatar.cc/150?u=${Uri.encodeComponent(identity)}';

  final bg = _colorFor(identity);

  return Container(
    width: size,
    height: size,
    decoration: BoxDecoration(shape: BoxShape.circle, color: bg),
    child: ClipOval(
      child: Image.network(
        url,
        width: size,
        height: size,
        fit: BoxFit.cover,
        errorBuilder: (_, __, ___) => _PersonPlaceholder(size: size, bg: bg),
      ),
    ),
  );
}

// ─── Colour helpers ───────────────────────────────────────────────────────────

const _kColors = [
  Color(0xFF1565C0),
  Color(0xFF6A1B9A),
  Color(0xFF00695C),
  Color(0xFFAD1457),
  Color(0xFF2E7D32),
  Color(0xFFE65100),
  Color(0xFF4E342E),
  Color(0xFF37474F),
  Color(0xFF880E4F),
  Color(0xFF1A237E),
];

Color _colorFor(String identity) {
  if (identity.isEmpty) return _kColors[0];
  final hash = identity.codeUnits.fold(0, (int a, int b) => (a * 17 + b) & 0x7FFFFFFF);
  return _kColors[hash % _kColors.length];
}

// ─── Fallback widget ──────────────────────────────────────────────────────────

class _PersonPlaceholder extends StatelessWidget {
  const _PersonPlaceholder({required this.size, required this.bg});
  final double size;
  final Color bg;

  @override
  Widget build(BuildContext context) {
    return Container(
      width: size,
      height: size,
      color: bg,
      alignment: Alignment.center,
      child: Icon(Icons.person, size: size * 0.55,
          color: Colors.white.withValues(alpha: 0.85)),
    );
  }
}

import 'dart:async';

import 'package:flutter/material.dart';

import '../../voice/twilio_voice.dart';
import '../../theme/twilio_theme.dart';
import '../../services/twilio_call_handler_service.dart';
import 'twilio_incoming_call_screen.dart';
import 'twilio_voice_call_screen.dart';

export '../../services/twilio_call_handler_service.dart' show TwilioCallHandlerService;

/// A widget that automatically handles incoming Twilio Voice calls.
///
/// Wrap your app's root widget (or any ancestor of your main Navigator) with
/// [TwilioCallHandler] and it will:
///
/// - Listen for incoming calls (both foreground FCM and live Voice SDK events)
/// - Show a bottom-sheet incoming call screen
/// - Navigate to the voice call screen on accept
/// - Detect if the app was launched from the SDK's [TwilioIncomingCallActivity]
///   (killed-app scenario) and go straight to the call screen if accepted
///
/// **Minimal usage:**
/// ```dart
/// MaterialApp(
///   home: TwilioCallHandler(
///     child: MyHomeScreen(),
///   ),
/// )
/// ```
///
/// **Custom token / accept flow:**
/// ```dart
/// TwilioCallHandler(
///   onAcceptCall: (callSid, from) async {
///     // fetch token, init voice SDK, then accept
///     await TwilioVoice.instance.acceptCall(callSid: callSid);
///   },
///   child: MyHomeScreen(),
/// )
/// ```
class TwilioCallHandler extends StatefulWidget {
  const TwilioCallHandler({
    super.key,
    required this.child,
    this.onAcceptCall,
    this.onRejectCall,
    this.theme,
  });

  /// The widget below this in the tree (typically your home screen).
  final Widget child;

  /// Called when the user taps Accept on the incoming call screen.
  ///
  /// If null the SDK calls [TwilioVoice.instance.acceptCall] automatically
  /// and navigates to [TwilioVoiceCallScreen].
  final Future<void> Function(String callSid, String from)? onAcceptCall;

  /// Called when the user taps Decline.  If null the SDK calls
  /// [TwilioVoice.instance.rejectCall] automatically.
  final Future<void> Function(String callSid)? onRejectCall;

  /// Optional theme override for the built-in call screens.
  final dynamic theme; // TwilioThemeData

  @override
  State<TwilioCallHandler> createState() => _TwilioCallHandlerState();
}

class _TwilioCallHandlerState extends State<TwilioCallHandler> {
  StreamSubscription<IncomingCallEvent>? _incomingCallSub;
  String? _activeCallSid; // deduplication guard

  @override
  void initState() {
    super.initState();

    // Listen for live incoming call events (app is foreground / Voice SDK active)
    _incomingCallSub = TwilioVoice.instance.onIncomingCall.listen((event) {
      if (!mounted) return;
      _handleIncoming(callSid: event.callSid, from: event.from ?? 'Unknown');
    });

    // After first frame: check if app was launched from TwilioIncomingCallActivity
    WidgetsBinding.instance.addPostFrameCallback((_) => _checkNativePending());
  }

  @override
  void dispose() {
    _incomingCallSub?.cancel();
    super.dispose();
  }

  // ── Native pending call (killed-app scenario) ──────────────────────────────

  Future<void> _checkNativePending() async {
    try {
      final result = await TwilioCallHandlerService.getPendingIncomingCall();
      if (result == null || !mounted) return;

      final callSid = result['callSid'] as String? ?? '';
      final from = result['from'] as String? ?? 'Unknown';
      final accepted = result['accepted'] as bool? ?? false;

      if (callSid.isEmpty) return;
      _activeCallSid = callSid;

      if (accepted) {
        // User already tapped Accept on the native screen — go straight to call
        await _doAccept(callSid: callSid, from: from);
      } else {
        // Launched by tapping the notification banner — show incoming screen
        _activeCallSid = null;
        _handleIncoming(callSid: callSid, from: from);
      }
    } catch (_) {
      // Not Android or method unavailable — ignore
    }
  }

  // ── Incoming call handling ─────────────────────────────────────────────────

  void _handleIncoming({required String callSid, required String from}) {
    if (_activeCallSid == callSid) return; // already handling
    _activeCallSid = callSid;

    final themeData = widget.theme ?? TwilioTheme.of(context);

    showModalBottomSheet(
      context: context,
      isDismissible: false,
      isScrollControlled: true,
      builder: (_) => TwilioIncomingCallScreen(
        callSid: callSid,
        from: from,
        theme: themeData,
        onAccepted: () async {
          Navigator.pop(context);
          await _doAccept(callSid: callSid, from: from);
        },
        onRejected: () async {
          _activeCallSid = null;
          Navigator.pop(context);
          if (widget.onRejectCall != null) {
            await widget.onRejectCall!(callSid);
          } else {
            await TwilioVoice.instance.rejectCall(callSid: callSid);
          }
        },
      ),
    ).whenComplete(() {
      // Reset guard if sheet dismissed without action
      if (_activeCallSid == callSid) _activeCallSid = null;
    });
  }

  Future<void> _doAccept({required String callSid, required String from}) async {
    final themeData = widget.theme ?? TwilioTheme.of(context);

    if (widget.onAcceptCall != null) {
      await widget.onAcceptCall!(callSid, from);
    } else {
      await TwilioVoice.instance.acceptCall(callSid: callSid);
    }

    if (!mounted) return;
    Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => TwilioVoiceCallScreen(
          callSid: callSid,
          remoteIdentity: from,
          theme: themeData,
          onCallEnded: () {
            _activeCallSid = null;
            Navigator.pop(context);
          },
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) => widget.child;
}

import 'dart:async';

import 'package:flutter/material.dart';

import '../../core/twilio_commkit.dart';
import '../../voice/twilio_voice.dart';
import '../../theme/twilio_theme.dart';
import '../../services/twilio_call_handler_service.dart';
import 'twilio_incoming_call_screen.dart';
import 'twilio_voice_call_screen.dart';

export '../../services/twilio_call_handler_service.dart' show TwilioCallHandlerService;

/// A widget that automatically handles incoming Twilio Voice calls.
///
/// Wrap your app's root widget (or any ancestor of your main Navigator) with
/// [TwilioCallHandler] and it will:
///
/// - Listen for incoming calls (both foreground FCM and live Voice SDK events)
/// - Show a bottom-sheet incoming call screen
/// - Navigate to the voice call screen on accept
/// - Detect if the app was launched from the SDK's [TwilioIncomingCallActivity]
///   (killed-app scenario) and go straight to the call screen if accepted
///
/// **Minimal usage:**
/// ```dart
/// MaterialApp(
///   home: TwilioCallHandler(
///     child: MyHomeScreen(),
///   ),
/// )
/// ```
///
/// **Custom token / accept flow:**
/// ```dart
/// TwilioCallHandler(
///   onAcceptCall: (callSid, from) async {
///     // fetch token, init voice SDK, then accept
///     await TwilioVoice.instance.acceptCall(callSid: callSid);
///   },
///   child: MyHomeScreen(),
/// )
/// ```
class TwilioCallHandler extends StatefulWidget {
  const TwilioCallHandler({
    super.key,
    required this.child,
    this.onAcceptCall,
    this.onRejectCall,
    this.theme,
  });

  /// The widget below this in the tree (typically your home screen).
  final Widget child;

  /// Called when the user taps Accept on the incoming call screen.
  ///
  /// If null the SDK calls [TwilioVoice.instance.acceptCall] automatically
  /// and navigates to [TwilioVoiceCallScreen].
  final Future<void> Function(String callSid, String from)? onAcceptCall;

  /// Called when the user taps Decline.  If null the SDK calls
  /// [TwilioVoice.instance.rejectCall] automatically.
  final Future<void> Function(String callSid)? onRejectCall;

  /// Optional theme override for the built-in call screens.
  final dynamic theme; // TwilioThemeData

  @override
  State<TwilioCallHandler> createState() => _TwilioCallHandlerState();
}

class _TwilioCallHandlerState extends State<TwilioCallHandler> {
  StreamSubscription<IncomingCallEvent>? _incomingCallSub;
  String? _activeCallSid; // deduplication guard

  @override
  void initState() {
    super.initState();
    // Check native pending FIRST (before stream subscription) so _activeCallSid
    // is set as a dedup guard before any platform events arrive.
    WidgetsBinding.instance.addPostFrameCallback((_) async {
      await _checkNativePending();
      // Only start listening AFTER native check so we don't race.
      _startListening();
    });
  }

  void _startListening() {
    _incomingCallSub = TwilioVoice.instance.onIncomingCall.listen((event) {
      if (!mounted) return;
      _handleIncoming(callSid: event.callSid, from: event.from ?? 'Unknown');
    });
  }

  @override
  void dispose() {
    _incomingCallSub?.cancel();
    super.dispose();
  }

  // ── Native pending call (killed-app scenario) ──────────────────────────────

  Future<void> _checkNativePending() async {
    try {
      final result = await TwilioCallHandlerService.getPendingIncomingCall();
      if (result == null || !mounted) return;

      final callSid = result['callSid'] as String? ?? '';
      final from = result['from'] as String? ?? 'Unknown';
      final accepted = result['accepted'] as bool? ?? false;

      if (callSid.isEmpty) return;

      // Set dedup guard immediately so the stream listener ignores this SID.
      _activeCallSid = callSid;

      if (accepted) {
        // User already tapped Accept on the native screen — init SDK then go
        // straight to the call screen.
        await _autoInitVoiceIfNeeded();
        if (!mounted) return;
        await _doAccept(callSid: callSid, from: from);
      } else {
        // Launched by tapping the notification banner — show incoming screen.
        _activeCallSid = null; // allow _handleIncoming to proceed
        _handleIncoming(callSid: callSid, from: from);
      }
    } catch (_) {
      // Not Android or method unavailable — ignore
    }
  }

  /// Ensures the Voice SDK is initialized before accepting a killed-app call.
  /// Uses the SDK's configured [accessTokenProvider] when available.
  Future<void> _autoInitVoiceIfNeeded() async {
    try {
      final provider = TwilioCommKit.config.accessTokenProvider;
      if (provider == null) return;
      final token = await provider();
      await TwilioVoice.instance.initialize(accessToken: token);
    } catch (_) {
      // Best-effort — acceptCall will fail gracefully if no invite is found.
    }
  }

  // ── Incoming call handling ─────────────────────────────────────────────────

  void _handleIncoming({required String callSid, required String from}) {
    if (_activeCallSid == callSid) return; // already handling
    _activeCallSid = callSid;

    final themeData = widget.theme ?? TwilioTheme.of(context);

    showModalBottomSheet(
      context: context,
      isDismissible: false,
      isScrollControlled: true,
      builder: (_) => TwilioIncomingCallScreen(
        callSid: callSid,
        from: from,
        theme: themeData,
        onAccepted: () async {
          Navigator.pop(context);
          await _doAccept(callSid: callSid, from: from);
        },
        onRejected: () async {
          _activeCallSid = null;
          Navigator.pop(context);
          if (widget.onRejectCall != null) {
            await widget.onRejectCall!(callSid);
          } else {
            await TwilioVoice.instance.rejectCall(callSid: callSid);
          }
        },
      ),
    ).whenComplete(() {
      // Reset guard if sheet dismissed without action
      if (_activeCallSid == callSid) _activeCallSid = null;
    });
  }

  Future<void> _doAccept({required String callSid, required String from}) async {
    final themeData = widget.theme ?? TwilioTheme.of(context);

    if (widget.onAcceptCall != null) {
      await widget.onAcceptCall!(callSid, from);
    } else {
      await TwilioVoice.instance.acceptCall(callSid: callSid);
    }

    if (!mounted) return;
    Navigator.push(
      context,
      MaterialPageRoute(
        builder: (_) => TwilioVoiceCallScreen(
          callSid: callSid,
          remoteIdentity: from,
          theme: themeData,
          onCallEnded: () {
            _activeCallSid = null;
            Navigator.pop(context);
          },
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) => widget.child;
}

import 'package:flutter_twilio_commkit_platform_interface/flutter_twilio_commkit_platform_interface.dart';

import '../config/twilio_commkit_config.dart';
import '../utils/twilio_logger.dart';
import '../video/twilio_video.dart';
import '../voice/twilio_voice.dart';
import '../chat/twilio_chat.dart';

export '../config/twilio_commkit_config.dart';

/// Entry point for the Flutter Twilio CommKit SDK.
///
/// Call [TwilioCommKit.initialize] once at app startup before using
/// [TwilioVideo] or [TwilioVoice].
class TwilioCommKit {
  TwilioCommKit._();

  static bool _initialized = false;
  static TwilioCommKitConfig? _config;

  /// Returns the current SDK configuration.
  static TwilioCommKitConfig get config {
    _assertInitialized();
    return _config!;
  }

  /// Initializes the SDK with project-specific Twilio credentials.
  ///
  /// Must be called once at app startup before using [TwilioVideo] or
  /// [TwilioVoice]. Each project supplies its own [TwilioCredentials].
  ///
  /// ```dart
  /// await TwilioCommKit.initialize(
  ///   config: TwilioCommKitConfig(
  ///     credentials: TwilioCredentials(
  ///       accountSid: 'ACxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx',
  ///       apiKeySid:  'SKxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx',
  ///       outgoingApplicationSid: 'APxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx',
  ///       pushCredentialSid:      'CRxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx',
  ///     ),
  ///     accessTokenProvider: () async => await myServer.fetchToken(),
  ///     videoConfig: TwilioVideoConfig(roomType: TwilioRoomType.group),
  ///     voiceConfig: TwilioVoiceConfig(callerIdName: 'MyApp'),
  ///     logLevel: TwilioLogLevel.debug,
  ///   ),
  /// );
  /// ```
  static Future<void> initialize({required TwilioCommKitConfig config}) async {
    if (_initialized) {
      TwilioLogger.warning('TwilioCommKit is already initialized.');
      return;
    }

    // Validate SID formats before touching native layer
    config.credentials.validate();

    _config = config;
    TwilioLogger.configure(config.logLevel);
    TwilioLogger.debug('TwilioCommKit initializing...');
    TwilioLogger.debug(
      'Credentials: ${config.credentials.toSafeMap()}',
    );

    await TwilioCommKitPlatform.instance.initialize(
      logLevel: config.logLevel.name,
      credentials: TwilioCredentialsModel(
        accountSid: config.credentials.accountSid,
        apiKeySid: config.credentials.apiKeySid,
        pushCredentialSid: config.credentials.pushCredentialSid,
        outgoingApplicationSid: config.credentials.outgoingApplicationSid,
      ),
      videoConfig: config.videoConfig.toMap(),
      voiceConfig: config.voiceConfig.toMap(),
    );

    _initialized = true;
    TwilioLogger.debug('TwilioCommKit initialized successfully.');
  }

  /// Disposes all SDK resources.
  static Future<void> dispose() async {
    TwilioVideo.instance.dispose();
    TwilioVoice.instance.dispose();
    _initialized = false;
    _config = null;
    TwilioLogger.debug('TwilioCommKit disposed.');
  }

  static void _assertInitialized() {
    assert(
      _initialized,
      'TwilioCommKit is not initialized. '
      'Call TwilioCommKit.initialize() first.',
    );
  }
}

